/**
 * SignalLimitOverlay — Blurred overlay for gated signals.
 * Shows "Unlock X more signals" with upgrade CTA.
 */
import { Link } from 'react-router-dom';
import useSignalTier from '../hooks/useSignalTier';

const UPGRADE_MAP = {
  explorer: { nextTier: 'Trader', path: '/pricing-plans' },
  trader: { nextTier: 'Pro', path: '/pricing-plans' },
};

export default function SignalLimitOverlay({ hiddenCount, totalCount, visibleCount }) {
  const { userTier, delayColor } = useSignalTier();

  if (!hiddenCount || hiddenCount <= 0) return null;

  const upgrade = UPGRADE_MAP[userTier] || UPGRADE_MAP.explorer;

  return (
    <div
      style={{
        position: 'relative',
        marginTop: -2,
      }}
    >
      {/* Gradient fade at bottom of visible table */}
      <div
        style={{
          position: 'absolute',
          top: -60,
          left: 0,
          right: 0,
          height: 60,
          background: 'linear-gradient(to bottom, transparent, var(--color-bg, #0B0F14))',
          pointerEvents: 'none',
          zIndex: 1,
        }}
      />
      {/* Overlay content */}
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          padding: '32px 24px',
          background: 'var(--color-surface, #0F1620)',
          border: '1px solid var(--color-border, #1F2A37)',
          borderRadius: 10,
          textAlign: 'center',
        }}
      >
        {/* Lock icon */}
        <div
          style={{
            width: 48,
            height: 48,
            borderRadius: 12,
            background: `${delayColor}12`,
            border: `2px solid ${delayColor}30`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            marginBottom: 12,
          }}
        >
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none"
            stroke={delayColor} strokeWidth="2" strokeLinecap="round">
            <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
            <path d="M7 11V7a5 5 0 0110 0v4" />
          </svg>
        </div>

        <div
          style={{
            fontSize: 15,
            fontWeight: 700,
            color: 'var(--color-text, #E5E7DB)',
            fontFamily: "'Plus Jakarta Sans', sans-serif",
            marginBottom: 4,
          }}
        >
          Unlock {hiddenCount} more signal{hiddenCount !== 1 ? 's' : ''}
        </div>
        <div
          style={{
            fontSize: 13,
            color: 'var(--color-text-secondary, #8899AA)',
            fontFamily: "'Plus Jakarta Sans', sans-serif",
            marginBottom: 16,
          }}
        >
          Showing {visibleCount} of {totalCount} signals.
          Upgrade to {upgrade.nextTier} to see {userTier === 'explorer' ? 'up to 20' : 'all'} signals.
        </div>

        <Link
          to={upgrade.path}
          style={{
            display: 'inline-flex',
            alignItems: 'center',
            gap: 6,
            padding: '10px 24px',
            borderRadius: 8,
            background: `linear-gradient(135deg, ${delayColor}, ${delayColor}CC)`,
            color: '#0B0F14',
            fontSize: 13,
            fontWeight: 700,
            fontFamily: "'Plus Jakarta Sans', sans-serif",
            textDecoration: 'none',
            boxShadow: `0 4px 16px ${delayColor}33`,
            transition: 'opacity 0.15s',
          }}
          onMouseEnter={(e) => { e.currentTarget.style.opacity = '0.85'; }}
          onMouseLeave={(e) => { e.currentTarget.style.opacity = '1'; }}
        >
          Upgrade to {upgrade.nextTier}
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
            stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
            <path d="M5 12h14M12 5l7 7-7 7" />
          </svg>
        </Link>
      </div>
    </div>
  );
}
