/**
 * SignalDelayBanner — Top banner showing delay status + upgrade CTA
 * Only shown for delayed tiers (explorer, trader).
 */
import { Link } from 'react-router-dom';
import useSignalTier from '../hooks/useSignalTier';
import { UPGRADE_PATH } from '../config/pricing';

const UPGRADE_MAP = {
  explorer: { nextTier: UPGRADE_PATH.explorer.nextLabel, price: UPGRADE_PATH.explorer.nextPrice, path: '/pricing-plans' },
  starter:  { nextTier: UPGRADE_PATH.starter.nextLabel,  price: UPGRADE_PATH.starter.nextPrice,  path: '/pricing-plans' },
  trader:   { nextTier: UPGRADE_PATH.trader.nextLabel,   price: UPGRADE_PATH.trader.nextPrice,   path: '/pricing-plans' },
};

export default function SignalDelayBanner() {
  const { userTier, delayMinutes, delayColor, isLive } = useSignalTier();

  if (isLive) return null;

  const upgrade = UPGRADE_MAP[userTier] || UPGRADE_MAP.explorer;

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        gap: 12,
        flexWrap: 'wrap',
        padding: '10px 16px',
        marginBottom: 16,
        borderRadius: 8,
        background: `${delayColor}0C`,
        border: `1px solid ${delayColor}30`,
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
        <svg
          width="16" height="16" viewBox="0 0 24 24" fill="none"
          stroke={delayColor} strokeWidth="2" strokeLinecap="round"
        >
          <circle cx="12" cy="12" r="10" />
          <polyline points="12 6 12 12 16 14" />
        </svg>
        <span
          style={{
            fontSize: 13,
            fontWeight: 600,
            color: 'var(--color-text, #E5E7DB)',
            fontFamily: "'Plus Jakarta Sans', sans-serif",
          }}
        >
          Signals delayed by {delayMinutes} min.{' '}
          <span style={{ color: 'var(--color-text-secondary, #8899AA)', fontWeight: 400 }}>
            Upgrade to {upgrade.nextTier} for {userTier === 'explorer' ? 'near real-time' : 'real-time'} delivery.
          </span>
        </span>
      </div>
      <Link
        to={upgrade.path}
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: 4,
          padding: '6px 16px',
          borderRadius: 6,
          background: delayColor,
          color: '#0B0F14',
          fontSize: 12,
          fontWeight: 700,
          fontFamily: "'Plus Jakarta Sans', sans-serif",
          textDecoration: 'none',
          whiteSpace: 'nowrap',
          transition: 'opacity 0.15s',
        }}
        onMouseEnter={(e) => { e.currentTarget.style.opacity = '0.85'; }}
        onMouseLeave={(e) => { e.currentTarget.style.opacity = '1'; }}
      >
        Get real-time signals
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
          stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
          <path d="M5 12h14M12 5l7 7-7 7" />
        </svg>
      </Link>
    </div>
  );
}
