/**
 * SignalTierBadge — Shows DELAYED / NEAR REAL-TIME / LIVE badge
 * Used in scanner tables to indicate signal delivery tier.
 */
import useSignalTier from '../hooks/useSignalTier';

export default function SignalTierBadge({ style }) {
  const { delayLabel, delayColor, badgeBg, isLive } = useSignalTier();

  return (
    <span
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: 5,
        padding: '3px 10px',
        borderRadius: 12,
        fontSize: 10,
        fontWeight: 700,
        fontFamily: "'JetBrains Mono', monospace",
        letterSpacing: '0.05em',
        color: delayColor,
        background: badgeBg,
        border: `1px solid ${delayColor}33`,
        whiteSpace: 'nowrap',
        ...style,
      }}
    >
      {isLive && (
        <span
          style={{
            width: 6,
            height: 6,
            borderRadius: '50%',
            background: delayColor,
            boxShadow: `0 0 6px ${delayColor}`,
            animation: 'signalLivePulse 2s ease-in-out infinite',
          }}
        />
      )}
      {delayLabel}
    </span>
  );
}
