import { useState, useEffect, useCallback } from 'react';
import { api } from '../utils/api';

export default function useScanners() {
  const [presets, setPresets] = useState([]);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);

  const fetchPresets = useCallback(async () => {
    const data = await api('/scanners', { silent: true });
    if (data) {
      const raw = data.presets || data;
      // Normalize presets: API may return object keyed by preset name
      if (Array.isArray(raw)) {
        setPresets(raw);
      } else if (typeof raw === 'object') {
        setPresets(Object.entries(raw).map(([key, v]) => ({
          key,
          name: v.name || key,
          description: v.description || '',
          strategies: v.strategies || [],
          ...v,
        })));
      }
    }
  }, []);

  useEffect(() => {
    fetchPresets();
  }, [fetchPresets]);

  /**
   * Normalize a raw match object into a consistent signal row.
   */
  function normalizeMatch(m) {
    let wr = m.win_rate ?? m.winrate ?? m.confidence ?? null;
    if (wr != null && wr > 1) wr = wr / 100;
    let tr = m.total_return ?? m.return_pct ?? m.price_change ?? null;
    if (tr != null && Math.abs(tr) > 5) tr = tr / 100;
    let mdd = m.max_drawdown ?? m.max_dd ?? null;
    if (mdd != null && mdd > 1) mdd = mdd / 100;
    return {
      symbol: m.symbol || m.ticker || '--',
      strategy: m.strategy || m.strategy_name || '--',
      region: m.region || 'us',
      sector: m.sector || null,
      win_rate: wr,
      total_return: tr,
      sharpe: m.sharpe_ratio ?? m.sharpe ?? null,
      max_dd: mdd,
      trades: m.trades ?? m.trade_count ?? 0,
      profit_factor: m.profit_factor ?? m.pf ?? null,
      signal_strength: m.signal_strength ?? Math.round((wr ?? 0) * 100),
      volume_ratio: m.volume_ratio ?? null,
      avg_volume: m.avg_volume ?? null,
      current_volume: m.current_volume ?? null,
      confidence: wr,
    };
  }

  /**
   * Extract matches array from various API response shapes.
   */
  function extractMatches(data) {
    if (!data) return [];
    if (Array.isArray(data.matches)) return data.matches;
    if (Array.isArray(data.signals)) return data.signals;
    if (Array.isArray(data.results)) return data.results;
    if (Array.isArray(data)) return data;
    return [];
  }

  const runScanner = useCallback(async (preset) => {
    setLoading(true);

    try {
      // Primary: fetch scanner preset
      const data = await api('/scanners/' + encodeURIComponent(preset), { silent: true });
      let matches = extractMatches(data);

      // If scanner preset returned results, use them
      if (matches.length > 0) {
        setResults(matches.map(normalizeMatch));
        setLoading(false);
        return data;
      }

      // Fallback 1: try live scanner signals
      const liveData = await api('/scanners/signals/live', { silent: true });
      matches = extractMatches(liveData);
      if (matches.length > 0) {
        setResults(matches.map(normalizeMatch));
        setLoading(false);
        return liveData;
      }

      // Fallback 2: try realtime signals
      const rtData = await api('/realtime/signals', { silent: true });
      matches = extractMatches(rtData);
      if (matches.length > 0) {
        setResults(matches.map(normalizeMatch));
        setLoading(false);
        return rtData;
      }

      // Fallback 3: try latest signals from v2 API
      const latestData = await api('/v2/data/signals/latest', { silent: true });
      matches = extractMatches(latestData);
      if (matches.length > 0) {
        setResults(matches.map(normalizeMatch));
        setLoading(false);
        return latestData;
      }

      // Fallback 4: try daily strategy signals
      const dailyData = await api('/aura_alpha/daily', { silent: true });
      matches = extractMatches(dailyData);
      if (matches.length > 0) {
        setResults(matches.map(normalizeMatch));
        setLoading(false);
        return dailyData;
      }

      // No data from any source
      setResults([]);
      setLoading(false);
      return null;
    } catch (err) {
      setResults([]);
      setLoading(false);
      throw err;
    }
  }, []);

  return { presets, runScanner, results, loading };
}
