/**
 * SignalAnalysisLock — Expandable "Signal Analysis" section per row.
 * Locked with blur overlay for explorer/starter tiers.
 * Shows detailed breakdown for trader+ tiers.
 */
import { useState } from 'react';
import { Link } from 'react-router-dom';
import useSignalTier from '../hooks/useSignalTier';

/**
 * The mock analysis content to show (blurred for locked tiers).
 */
function AnalysisContent({ row }) {
  const factors = [
    { name: 'Price Momentum', value: ((row.signal_strength || 50) * 0.8 + 10).toFixed(0) },
    { name: 'Volume Confirmation', value: ((row.trades || 20) > 50 ? 82 : 45) },
    { name: 'Trend Alignment', value: ((row.sharpe || 0) > 1 ? 78 : 38) },
    { name: 'Risk/Reward', value: ((row.profit_factor || 1) > 1.5 ? 85 : 42) },
  ];

  return (
    <div style={{ padding: '12px 16px', display: 'flex', gap: 16, flexWrap: 'wrap' }}>
      {/* Factor Breakdown */}
      <div style={{ flex: '1 1 200px' }}>
        <div style={{
          fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5,
          color: 'var(--color-text-secondary, #8899AA)', marginBottom: 8,
        }}>
          Signal Factors
        </div>
        {factors.map((f) => (
          <div key={f.name} style={{
            display: 'flex', alignItems: 'center', justifyContent: 'space-between',
            padding: '4px 0', fontSize: 12,
          }}>
            <span style={{ color: 'var(--color-text-secondary, #8899AA)' }}>{f.name}</span>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <div style={{
                width: 48, height: 5, borderRadius: 3,
                background: 'var(--color-surface-hover, #1A2332)',
                overflow: 'hidden',
              }}>
                <div style={{
                  width: `${Math.min(100, f.value)}%`,
                  height: '100%',
                  borderRadius: 3,
                  background: f.value >= 65 ? 'var(--color-green, #22C55E)'
                    : f.value >= 40 ? 'var(--color-amber, #D29922)'
                    : 'var(--color-red, #EF4444)',
                }} />
              </div>
              <span style={{
                fontFamily: "'JetBrains Mono', monospace",
                fontWeight: 600,
                color: f.value >= 65 ? 'var(--color-green, #22C55E)'
                  : f.value >= 40 ? 'var(--color-amber, #D29922)'
                  : 'var(--color-red, #EF4444)',
              }}>
                {f.value}
              </span>
            </div>
          </div>
        ))}
      </div>
      {/* Signal Strength Gauge */}
      <div style={{ flex: '0 0 120px', textAlign: 'center' }}>
        <div style={{
          fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5,
          color: 'var(--color-text-secondary, #8899AA)', marginBottom: 8,
        }}>
          Overall Strength
        </div>
        <div style={{
          width: 64, height: 64, borderRadius: '50%', margin: '0 auto',
          background: `conic-gradient(
            var(--color-green, #22C55E) ${(row.signal_strength || 50)}%,
            var(--color-surface-hover, #1A2332) ${(row.signal_strength || 50)}%
          )`,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}>
          <div style={{
            width: 48, height: 48, borderRadius: '50%',
            background: 'var(--color-surface, #0F1620)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 16, fontWeight: 800,
            fontFamily: "'JetBrains Mono', monospace",
            color: 'var(--color-text, #E5E7DB)',
          }}>
            {Math.round(row.signal_strength || 50)}
          </div>
        </div>
      </div>
    </div>
  );
}

export default function SignalAnalysisLock({ row }) {
  const { canViewAnalysis, delayColor } = useSignalTier();
  const [expanded, setExpanded] = useState(false);

  return (
    <div style={{ borderTop: '1px solid var(--color-border, #1F2A37)' }}>
      <button
        onClick={(e) => { e.stopPropagation(); setExpanded(!expanded); }}
        style={{
          display: 'flex', alignItems: 'center', gap: 6,
          width: '100%', padding: '8px 16px', border: 'none',
          background: 'transparent', cursor: 'pointer',
          fontSize: 11, fontWeight: 600,
          color: 'var(--color-text-secondary, #8899AA)',
          fontFamily: "'JetBrains Mono', monospace",
        }}
      >
        <svg
          width="12" height="12" viewBox="0 0 24 24" fill="none"
          stroke="currentColor" strokeWidth="2" strokeLinecap="round"
          style={{
            transform: expanded ? 'rotate(180deg)' : 'rotate(0deg)',
            transition: 'transform 0.15s ease',
          }}
        >
          <polyline points="6 9 12 15 18 9" />
        </svg>
        Signal Analysis
        {!canViewAnalysis && (
          <svg width="10" height="10" viewBox="0 0 24 24" fill="none"
            stroke="currentColor" strokeWidth="2.5" style={{ marginLeft: 2 }}>
            <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
            <path d="M7 11V7a5 5 0 0110 0v4" />
          </svg>
        )}
      </button>

      {expanded && (
        <div style={{ position: 'relative' }}>
          {canViewAnalysis ? (
            <AnalysisContent row={row} />
          ) : (
            <>
              {/* Blurred content */}
              <div style={{
                filter: 'blur(6px)', opacity: 0.4, pointerEvents: 'none', userSelect: 'none',
              }}>
                <AnalysisContent row={row} />
              </div>
              {/* Lock overlay */}
              <div style={{
                position: 'absolute', inset: 0,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                background: 'rgba(11,15,20,0.6)',
                backdropFilter: 'blur(3px)',
                WebkitBackdropFilter: 'blur(3px)',
                borderRadius: 4,
              }}>
                <div style={{ textAlign: 'center', padding: 16 }}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none"
                    stroke={delayColor} strokeWidth="2" style={{ marginBottom: 6 }}>
                    <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                    <path d="M7 11V7a5 5 0 0110 0v4" />
                  </svg>
                  <div style={{
                    fontSize: 12, fontWeight: 700,
                    color: 'var(--color-text, #E5E7DB)',
                    fontFamily: "'Plus Jakarta Sans', sans-serif",
                    marginBottom: 6,
                  }}>
                    Detailed analysis requires Trader
                  </div>
                  <Link
                    to="/pricing-plans"
                    onClick={(e) => e.stopPropagation()}
                    style={{
                      fontSize: 11, fontWeight: 700, color: delayColor,
                      textDecoration: 'none',
                    }}
                  >
                    Upgrade now &rarr;
                  </Link>
                </div>
              </div>
            </>
          )}
        </div>
      )}
    </div>
  );
}
